import { useEffect, useState } from "react";
import UrunCard from "../components/UrunCard";

export default function Home() {
  const [urunler, setUrunler] = useState([]);
  const [aktifKategori, setAktifKategori] = useState("tumu");
  const [arama, setArama] = useState("");
  const [sirala, setSirala] = useState("varsayilan");

  useEffect(() => {
    const veriler = localStorage.getItem("urunler");
    if (veriler) setUrunler(JSON.parse(veriler));
  }, []);

  const kategoriler = [
    "tumu",
    ...new Set(urunler.map((u) => u.kategori).filter(Boolean)),
  ];

  let filtrelenmis = urunler
    .filter((u) => aktifKategori === "tumu" || u.kategori === aktifKategori)
    .filter((u) => u.ad.toLowerCase().includes(arama.toLowerCase()));

  if (sirala === "artan") {
    filtrelenmis.sort((a, b) => a.fiyat - b.fiyat);
  } else if (sirala === "azalan") {
    filtrelenmis.sort((a, b) => b.fiyat - a.fiyat);
  }

  return (
    <div className="max-w-6xl mx-auto p-6">
      <h1 className="text-2xl font-bold mb-4">Ürünler</h1>

      <div className="flex flex-wrap gap-4 mb-6">
        <select
          value={aktifKategori}
          onChange={(e) => setAktifKategori(e.target.value)}
          className="border px-3 py-2 rounded"
        >
          {kategoriler.map((kat, i) => (
            <option key={i} value={kat}>
              {kat.toUpperCase()}
            </option>
          ))}
        </select>

        <select
          value={sirala}
          onChange={(e) => setSirala(e.target.value)}
          className="border px-3 py-2 rounded"
        >
          <option value="varsayilan">Sıralama</option>
          <option value="artan">Fiyat Artan</option>
          <option value="azalan">Fiyat Azalan</option>
        </select>

        <input
          type="text"
          placeholder="Ara..."
          value={arama}
          onChange={(e) => setArama(e.target.value)}
          className="border px-3 py-2 rounded w-full sm:w-1/3"
        />
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-6">
        {filtrelenmis.map((urun) => (
          <UrunCard key={urun.id} urun={urun} />
        ))}
      </div>
    </div>
  );
}
